1	// claim-office.ts
2	
3	export type Customer = {
4	  yearsWithMHPCO: number;
5	  previousContracts?: number;
6	};
7	
8	export type Item = {
9	  type: string;
10	  material?: string;
11	  enchantment?: number;
12	  cursed?: boolean;
13	};
14	
15	export type QuoteInput = {
16	  customer: Customer;
17	  items: Item[];
18	};
19	
20	const PROCESSING_FEE = 5;
21	const FIRST_INSURANCE_RATE = 0.1;
22	const CURSED_SURCHARGE_RATE = 0.5;
23	const COMPONENT_BASE = 25;
24	const COMPONENT_BLOCK_PREMIUM = 60;
25	
26	const ITEM_BASE_PREMIUMS: Record<string, number> = {
27	  sword: 100,
28	  amulet: 60,
29	  staff: 80,
30	  potion: 40,
31	  rune: 25,
32	  moonstone: 25,
33	};
34	
35	function isComponentType(type: string): boolean {
36	  return ITEM_BASE_PREMIUMS[type] === COMPONENT_BASE;
37	}
38	
39	function groupItemsByType(items: Item[]): Map<string, Item[]> {
40	  const groups = new Map<string, Item[]>();
41	  for (const item of items) {
42	    const group = groups.get(item.type) ?? [];
43	    group.push(item);
44	    groups.set(item.type, group);
45	  }
46	  return groups;
47	}
48	
49	function calculateItemBase(type: string, item: Item): number {
50	  const base = ITEM_BASE_PREMIUMS[type];
51	  const cursedSurcharge = item.cursed ? base * CURSED_SURCHARGE_RATE : 0;
52	  return base + cursedSurcharge;
53	}
54	
55	function calculateGroupBase(type: string, group: Item[]): number {
56	  if (isComponentType(type) && group.length === 3) {
57	    return COMPONENT_BLOCK_PREMIUM;
58	  }
59	  return group.reduce((sum, item) => sum + calculateItemBase(type, item), 0);
60	}
61	
62	function calculatePolicyBase(items: Item[]): number {
63	  const groups = groupItemsByType(items);
64	  return Array.from(groups).reduce(
65	    (total, [type, group]) => total + calculateGroupBase(type, group),
66	    0
67	  );
68	}
69	
70	export function quote(input: QuoteInput): number {
71	  const policyBase = calculatePolicyBase(input.items);
72	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_RATE;
73	  return Math.ceil(policyBase + firstInsuranceSurcharge + PROCESSING_FEE);
74	}
